INSERT INTO `infos` VALUES ('5','1','about','9','MCSL - Marble Content System Laravel','mcsl.jpg','mcsl_big.jpg','2019-11-30 23:00:00','2025-07-06 16:45:46','Alles über <b>MCSL</b> und wie es endstanden ist.','<b>M</b>arble <b>C</b>ontent <b>S</b>ystem <b>L</b>aravel kurz <b>MCSL</b> ist ein 3 Säulen Webseiten System.<br />Datenbank, PHP-Code und Desing-Vorlagen werden getrennt voneinander gespeichert,<br />was eine größtmögliche Flexibilität und Variabilität ermöglicht.<br /><br /><b>MCSL</b> basiert auf PHP/MySQL und ist für fast jede art von Websites geeignet.<br />Es verfügt über ein Umfangreiches Administrationspanel<br />und kann von überall auf der Welt mit Daten versorgt werden.<br /><br />Entstanden ist <b>MCSL</b> aus <b>MCS</b>,<br />welches von der art der Verknüpfungen und Tiefe so umfangreich war,<br />das ein neues System hermusste welches alle nötigen Aufgaben übernimmt,<br />so das Verlinkung, Administration und Organisation vereinfacht werden.<br /><br />Mit der Zeit kamen immer mehr neue Features hinzu so das ein recht Komplexes Gebilde dabei raus kam.<br />Noch heute arbeiten wir an neuen Feldtypen und Funktionen welche die Arbeit mit<br /><b>MCSL</b> weiter vereinfachen und verbessern. :mcsl: - <b>Marble Content System Laravel</b>- is ready to launch');
INSERT INTO `infos` VALUES ('11','1','history','13','Die Geschichte von Marble FX','mcs_history.jpg','mcs_history_big.jpg','2025-07-06 13:56:52','2025-08-29 15:38:38','Marble FX entstand im Jahr 2001 an einem klaren Sommerabend auf dem Balkon meiner Mutter.','<p>Marble FX entstand im Jahr 2001 an einem klaren Sommerabend auf dem Balkon meiner Mutter.</p><p>Mir und meinem Freund Mirko kam die Idee, eine eigene Firma zu gründen.</p><p>Bewaffnet mit dieser Idee machten wir uns daran, ein erstes Logo zu entwickeln.</p><p>Daraufhin entstand ein Flash-Intro, das die Jungs von Paliva dann noch vertonten.</p><p><br /></p><p>2002/03 folgten mehrere Websites unter dem Label Marble FX.</p><p>Auf Anraten von Pixelmonsta beschäftigte ich mich mit PHP/MySQL.</p><p><br /></p><p>2004 verbrachte ich den Großteil meiner Zeit mit Programmieren und dem Studieren von FAQs und Dokumentationen.</p><p>Nachdem der Reha-Fair-Katalog fertig war, bat mich Rosi, seine Seite auf PHP zu portieren.</p><p><br /></p><p>2005 begann ich mit der Arbeit an einem neuen System, dem Marble Content System.</p><p>Dieses kam bis vor kurzem bei Marble FX zum Einsatz.</p><p>Mittlerweile habe ich MCSL aus der Taufe gehoben, eine komplette Neuentwicklung mit Laravel/Vue.js, die auch Grundlage dieser Seite ist.</p><p><br /></p><p>Asario</p>');
