INSERT INTO `infos` VALUES ('14','1','about','10','About Us','about.jpg','about_big.jpg','2018-11-26 23:00:00','2012-12-31 23:00:00','Marble FX Steht f&uuml;r Solide und doch Effektreiche Multimedia Produktionen.','Marble FX Steht f&uuml;r Solide und doch Effektreiche Multimedia Produktionen.\r\n\r\nWir wollen das Sie was auch immer sie zu pr&auml;sentieren haben gut dastehn.\r\nDenn &Ouml;ffentlichkeitsarbeit ist nach wie vor wichtig.\r\n\r\nWir entwickeln Ihre Online Strategie und den passenden Internetauftritt dazu.\r\nvon einer einfachen Internetseite &uuml;ber Online Shops bis zum Webportal ist bei uns alles zu finden.\r\n\r\n<b>Zu Unserem Repoirtoir geh&ouml;ren:</b>\r\n<ul><li class=\\\"duli\\\">Dynamische Webseiten </li><li class=\\\"duli\\\">Animierte Webseiten </li><li class=\\\"duli\\\">Pr&auml;sentationen </li><li class=\\\"duli\\\">Grafiken </li><li class=\\\"duli\\\">Flyer </li><li class=\\\"duli\\\">Logos   </li></ul>');
INSERT INTO `infos` VALUES ('15','1','about','1','Webdesign Heute','web_actual.jpg','web_actual_big.jpg','2025-07-06 13:56:52','2026-01-25 16:26:02','Was ist Webdesign heute.','Die zeiten wo statische Inhalte auf starren Seitenkonstruktionen rumoxidierten sind vorbei.<br />Heute zählt mehr und mehr Dynamik in diesem doch so dynamischen Medium.<br />Immer mehr Seiten gehen ins Netz und die Flut überfordert oftmals den Nutzer.<br /><br />Es ist heutzutage nicht nur wichtig eine Seite zu haben sie muss auch funktional sein<br />und dem Nutzer viele Möglichkeiten geben zu Interagieren.<br />Kommentar/Bewertungsfunktionen, Foren, Benutzeraccounts zum Personalisieren<br />uvm. gehören heute fast schon zum guten Ton.<br /><br />Das Web hat in den letzten Jahren eine Wandlung von einem Redakteur/Benutzer-System<br />zu einem Benutzer/Benutzer-System gemacht.<br />Jeder kann heute in Blogs und Foren sein Leben darlegen was wiederum dazu führt das Wissen allgegenwärtig ist.<br /><br />Projekte wie wikipedia, Instagram, Tik-Tok, Facebook und youtube weisen die Zukunft.<br />Weg von Seiten die von den Redakteuren gepflegt werden hin zu Communitys und<br />Benutzerengagement.<br /><br />Wir sehen einer Zukunft entgegen in der alle am Web mitarbeiten.');
