  `img_bild` varchar(255) DEFAULT NULL,
  `users_id` int(11) NOT NULL DEFAULT 0,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=56 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

INSERT INTO `news` VALUES ('1','1','2019-02-02 15:00:10','36','www.marblefx.de online','Herzlich willkommen auf www.marblefx.de Ihrem Webdienstleister mit Profil.\r\nHier finden sie alles zum Thema Marble Content System (kurz MCS)\r\nViel Spass wünscht euer Asario','','1','2012-11-25 08:10:00','2012-11-25 08:10:00');
INSERT INTO `news` VALUES ('3','1','2019-02-02 15:00:10','35','MCS v. 1.67 erschienen','Marble Content System v. 1.67 (Thoughtless Tension) wurde verÃ¶ffentlicht.\r\nWÃ¼nsche viel SpaÃŸ mit diesem Release. huldig','','1','2012-11-25 08:16:07','2012-11-25 08:16:07');
INSERT INTO `news` VALUES ('6','1','2014-02-13 15:12:10','34','MCS v. 1.68 released','MCS Version 1.68 - \"Honky Donkey\" wurde Released.\r\nMehr dazu im fx_lxk(index.php?page=infos&action=details&id=16|||Changelog).\r\nIch wÃ¼nsche euch viel Spass auf meinen Seiten.','','1','2013-05-17 13:49:54','2013-05-17 13:49:54');
INSERT INTO `news` VALUES ('7','1','2019-02-02 15:00:10','33','MCS v. 1.69 Online','Ein neues Release wurde Online gestellt,\r\nmehr infos siehe <a href=\"index.php?page=infos&action=details&id=16\">Changelog</a>','','1','2014-02-25 16:47:13','2014-02-25 16:47:13');
INSERT INTO `news` VALUES ('8','1','2019-02-02 15:00:10','32','MCS v. 1.70 released','Wie Ihr Vielleicht seht, habe ich www.marblefx.de renoviert.\r\nMit Version 1.70 hÃ¤lt das Foundation Framework Einzug in MCS. Mehr Infos siehe fx_lxk(http://www.marblefx.de/index.php?page=infos&action=details&id=16|||Changelog)\r\nbis bald, Asario','','1','2014-10-25 14:49:05','2014-10-25 14:49:05');
INSERT INTO `news` VALUES ('9','1','2019-02-02 15:00:10','31','MCS v. 1.72 VerÃ¶ffentlicht','Mal wieder hab ich gearbeitet das MCS noch sicherer wird.\nEinige nette Details wurden eingebaut.\nmehr dazu im fx_lxk(index.php?page=infos&amp;action=details&amp;id=16|||Changelog)','','1','2015-03-31 17:43:25','2015-03-31 17:43:25');
INSERT INTO `news` VALUES ('10','1','2019-02-02 15:00:10','30','MCS v. 1.85 ist eingetroffen....','Vor ein paar Wochen kamen die Updategeister angekrochen und haben die MCS Version 1.85 verloren. Ich konnte Sie aufsammeln und Einspielen.\nmehr Infos siehe fx_lxk(index.php?page=infos&action=details&id=16|||Changelog)','','1','2015-09-29 18:08:46','2015-09-29 18:08:46');
INSERT INTO `news` VALUES ('11','1','2019-02-02 15:00:10','29','MCS 1.89','Mal wieder was neues von der MCS-Front.\nHoffe ihr habt SpaÃŸ mit Version 1.89.\nnÃ¤here Infos siehe <a href=\\\"index.php?page=infos&action=details&id=16\\\">Changelog</a>','','1','2016-02-08 17:16:21','2016-02-08 17:16:21');
INSERT INTO `news` VALUES ('12','1','2019-02-02 15:00:10','28','MCS 1.98 verÃ¶ffentlicht','Habe mal wieder geschraubt und gearbeitet um MCS noch komfortabler zu machen,\nMehr Infos siehe <a href=\\\"index.php?page=infos&action=details&id=16\\\">Changelog</a>.','','1','2016-05-24 16:23:42','2016-05-24 16:23:42');
INSERT INTO `news` VALUES ('14','1','2019-02-02 15:00:10','27','Neues von MCS','Immer mal wieder was neues gibt es an dieser Stelle.\r\nMCS 2.01 ist fertig.\r\nMehr infos wie immer siehe <a href=\\\"infos-details-16\\\">Changelog</a>','','1','2016-07-17 06:56:20','2016-07-17 06:56:20');
INSERT INTO `news` VALUES ('15','1','2019-02-02 15:00:10','26','Das gute alte neue MCS','Mal wieder habe ich eine neue Version von MCS entwickelt.\r\nMehr Infos siehe <a href=\\\"infos-details-16\\\">Changelog</a>\r\nBis Bald, Asario','','1','2017-02-24 13:17:33','2017-02-24 13:17:33');
INSERT INTO `news` VALUES ('16','1','2019-02-02 15:00:10','25','MCS 2.35 Released','Wie schon oft habe ich MCS weiterentwickelt und nun ist Version 2.35 erschienen.\r\nWeitere Infos siehe <a href=\\\"infos-details-16\\\">Changelog</a>\r\nWÃ¼msche Viel SpaÃŸ mit diesem Relaease, \r\nin Love, Asario','','1','2017-05-26 13:18:49','2017-05-26 13:18:49');
INSERT INTO `news` VALUES ('17','1','2019-02-02 15:00:10','24','Mal wieder Updates...','Und schon wieder habe ich MCS aktualisiert..\nInfos wie immer im <a href=\\\"infos-details-16\\\">Changelog</a>','','1','2017-07-16 18:46:00','2017-07-16 18:46:00');
INSERT INTO `news` VALUES ('18','1','2019-02-02 15:00:10','23','Version 2.65 Online','Es ist etliches neues Programmiert worden um MCS noch besser zu machen, \r\nIch hoffe es gefÃ¤llt euch. Weitere Infos siehe <a href=\\\"infos-details-16\\\">Changelog</a>.','','1','2017-11-05 09:25:10','2017-11-05 09:25:10');
INSERT INTO `news` VALUES ('19','1','2019-02-02 15:00:10','22','Verbessertes Layout','Ich habe mal wieder Hand angelegt und www.marblefx.de besser fÃ¼r MobilgerÃ¤te gemacht.\r\nIst ne kleine DetailverÃ¤nderung die groÃŸe Wirkung hat.\r\nHoffe ihr habt jetzt mehr SpaÃŸ mit euren mobilen Gadgets.\r\nEdit: Habe die Images Seite Ã¼berarbeitet.\r\nbis denne, Asario','','1','2017-11-25 18:55:49','2017-11-25 18:55:49');
INSERT INTO `news` VALUES ('20','1','2019-02-02 15:00:10','21','Schon wieder neue MCS Version','Habe mal wieder am Fundament geschraubt und MCS erweitert.\r\nWeitere Infos sind wie immer im <a href=\\\"changelog\\\">Changelog</a> zu finden.','','1','2018-02-04 15:17:09','2018-02-04 15:17:09');
INSERT INTO `news` VALUES ('21','1','2019-02-02 15:00:10','20','News from MCS...','Version 2.71 wurde eingespielt. Auch in diesem Release gibt es Neuerungen die Ihr im <a href=\\\"changelog\\\">Changelog</a> erfahrt. Viel SpaÃŸ auf meinen Seiten, Asario','','1','2018-04-08 09:54:07','2018-04-08 09:54:07');
INSERT INTO `news` VALUES ('22','1','2019-02-02 15:00:10','19','Neue Galerie wurde eingerichtetÂ ','Unter <a href=\\\"images-gallery-33\\\">Images-&gt;2015-2017</a> findet Ihr frische Shotz. Hoffe der ein oder andere mag meine Bilder. Ich sammele schon Bilder fÃ¼r die nÃ¤chste Galerie.\nIn Love, Asario','','1','2018-05-12 20:11:00','2018-05-12 20:11:00');
INSERT INTO `news` VALUES ('23','1','2019-02-02 15:00:10','18','Ferienzeit ist Surfzeit','Auch in diesen Ferien k&ouml;nnen Sie Surfen bis der Arzt kommt.\r\nAuf meinen MCS-Seiten ist eine neue Version von MCS erschienen.\r\nVersion 2.87 ist umfangreich ausgestattet und hat etliches verbessert.\r\nWeitere Infos siehe <a href=\\&quot;changelog\\&quot;>Changelog</a>.\r\nW&uuml;nsche viel Spa&szlig; auf meinen Seiten.','','1','2018-07-13 18:16:59','2018-07-13 18:16:59');
INSERT INTO `news` VALUES ('24','1','2019-02-02 15:00:10','17','MCS 2.88 published','Habe mal wieder ein neues Release fertiggestellt. Ist Haupts&auml;chlich ein kleineres Release mit vielen kleinen Ver&auml;nderungen.\nDie meisten &Auml;nderungen betreffen nur einzelne Seiten die mit MCS realisiert wurden.\nIch w&uuml;nsche viel Spa&szlig; mit MCS 2.88, in love Asario','','1','2019-01-19 14:26:51','2019-01-19 14:26:51');
INSERT INTO `news` VALUES ('25','1','2019-04-28 15:07:00','16','MCS 2.89 Online just now','Neue MCS Version Online. Weitere Infos wie immer im <a href=\\&quot;changelog\\&quot;>Changelog</a>.\r\nHaupts&auml;chlich habe ich einige Probleme in Verbindung mit meiner PHP Version gefixed.\r\nAnsonsten eher kleinere Bugs behoben, und einiges erneuert. Nichtsdestotrotz viel Spa&szlig; mit MCS 2.89.','','1','2019-02-10 15:49:39','2019-02-10 15:49:39');
INSERT INTO `news` VALUES ('26','1','2019-07-23 12:07:00','15','Neues Major Release von MCS','Auch dieses mal habe ich an MCS geschraubt und gearbeitet. Viele kleine &Auml;nderungen sind in Version 2.90 eingeflossen. Weitere Infos siehe <a href=\\&quot;changelog\\&quot;>Changelog</a>. W&uuml;nsche wie immer viel Spa&szlig; auf meinen Seiten, Asario.','','1','2019-07-23 12:07:00','2019-07-23 12:07:00');
INSERT INTO `news` VALUES ('27','1','2019-11-02 23:00:00','14','MCS Version 2.91 jetzt Online','Mal wieder hat sich einiges in MCS ge&auml;ndert. Neue Module zum Schnellzugriff auf Logs und ein Download-Kontroll-Modul  sind dazugekommen.\r\nWie immer haben sich auch ein paar Bugs zum fixen gefunden.\r\nMehr Infos wie immer im <a href=\\&quot;changelog\\&quot;>changelog</a>.','','1','2019-10-11 22:00:00','2019-10-11 22:00:00');
INSERT INTO `news` VALUES ('28','1','2020-03-02 05:18:00','13','MCS 2.92 has arrived','Auch dieses Jahr gibt es neues an der MCS Front.<br />Wünsche viel Spass auf meinen Seiten.<br /><br />Mehr Infos wie immer im <a href=\"http://mfx.localhost.de/changelog_old\">MCS Changelog</a>','','1','2020-02-09 13:15:24','2025-07-22 15:59:39');
INSERT INTO `news` VALUES ('38','1','2020-09-09 22:00:00','12','MCS Number 2.93 is online','Wie immer einiges neu in MCS.<br />Version 2.93 ist Online and working.<br />Das Cookie Window wurde überarbeitet und läuft jetzt ohne Probleme.<br />Weitere Infos wie immer im <a href=\"http://mfx.localhost.de/changelog_old\">MCS Changelog</a>','','1','2020-10-17 10:45:56','2025-07-22 15:59:01');
INSERT INTO `news` VALUES ('39','1','2021-10-18 16:40:23','11','MCS 2.95 activated','Wir haben mal wieder am MCS geschraubt und ein neues Projekt ist am entstehen.\nWas genau ist mein kleines Geheimnis aber es wird Gross.\nHoffe Ihr genie&szlig;t meine Seiten, in love, Asario','','1','2021-10-18 16:40:23','2021-10-18 16:40:23');
INSERT INTO `news` VALUES ('40','1','2022-11-07 23:00:00','10','MCS  V. 3.59.2','Auch diesmal hat sich einiges Verändert.<br />Einige größere und kleinere Fehler wurden behoben und MCS ist sicherer geworden.<br />Mehr wie immer im <a href=\"http://mfx.localhost.de/changelog_old\">MCS Changelog</a> Wünsche viel Spaß auf meinen Seiten, in Love, Asario','','1','2022-11-07 19:11:28','2025-07-22 15:58:33');
INSERT INTO `news` VALUES ('46','1','2023-10-08 09:20:25','9','MCS news over the World','Auch dieses mal hab ich an MCS geschraubt und einiges verbessert.\r\nArbeite momentan noch am Upload Script, wo noch einiges im argen ist.\r\nAber ich hoffe ich habe das bald hinter mir.\r\nIn Love, Asario','','1','2023-10-08 09:20:25','2025-06-30 18:42:00');
INSERT INTO `news` VALUES ('47','1','2023-12-09 23:00:00','8','Version 3.98.4 Online','Nach der 2 Faktor authentifizierung habt ich wieder einiges verbessert.<br />Weitere Infos im wie immer im <a href=\"/changelog_old\">MCS Changelog</a><a href=\"http://mfx.localhost.de/changelog_old\"></a>','','1','2023-11-25 14:55:50','2025-07-22 15:58:06');
INSERT INTO `news` VALUES ('48','1','2023-12-23 23:00:00','7','Happy Christmas under the Tree','Ich w&uuml;nsche Ihnen ein frohes Fest.\r\nP&uuml;nktlich zum Jahreswechsel ist Version 4.00.2 von MCS erschienen.\r\nW&uuml;nsche ein besinnliches Fest.','','1','2023-12-12 15:50:34','2025-06-30 18:42:00');
INSERT INTO `news` VALUES ('49','1','2024-07-14 22:00:00','6','MCS 4.00.8 finished','Mal wieder wurde einiges an MCS geschraubt um es noch besser zu machen.\r\nHope you enjoy, Asario','','1','2024-07-14 08:01:06','2025-06-30 18:42:00');
INSERT INTO `news` VALUES ('50','1','2024-09-27 17:56:00','5','MCS 4.25.2 ist angekommen','Da ich zur Zeit an einem anderen Projekt arbeite kommen bis auf weiteres keine neuen Features bei MCS an. Bugs werden aber nach wie vor behoben sobald sie zum Vorschein kommen. wüÃ¼nsche viel SpaÃŸ auf meinen Seiten, in love, Asario','','1','2024-09-27 17:53:38','2025-06-30 19:41:16');
INSERT INTO `news` VALUES ('51','1','2025-07-03 19:00:20','4','MCSL is Online','Ich habe MarbleFX.de auf <b>MCSL</b> Portiert.<div>MCSL ist eine komplette Neuentwicklung basierend auf Laravel &amp; Vue.</div><div>Infos wie immer im <a href=\"http://mfx.localhost.de/changelog_old\"></a><a href=\"/changelog\">MCSL Changelog</a></div>',NULL,'1','2025-07-03 19:00:20','2025-07-22 16:01:20');
INSERT INTO `news` VALUES ('52','1','2025-11-25 15:55:05','3','MCSL wurde erweitert.','2 Große Brocken habe ich gewuppt.<div><ol><li> Email/Newsletter Center &amp;amp;</li><li> Private Nachrichten auf <a href=\"https://www.asario.de\">www.asario.de</a><br />Nicht vergessen, anmelden auf <a href=\"https://www.asario.de/register\">www.asario.de/register</a><br />hoffe Ihr habt Spaß, Asario<br /></li></ol></div>',NULL,'1','2025-11-25 15:55:05','2025-12-27 17:49:29');
INSERT INTO `news` VALUES ('54','1','2025-12-27 17:50:12','2','Neues Jahr neues Glück','Hoffe Ihr hattet ein besinnliches Fest und wartet freudig auf Sylvester.<br />Mittlerweile kann man sich bei meinen Seiten per <b>Google Signin</b> anmelden.<div>Des weiteren habe ich einige Bugs gefixt, siehe <a href=\"https://www.marblefx.de/changelog\">MCSL Changelog</a><a href=\"https://www.marblefx.de/changelog\"></a><br /><div>Habt Spaß, und bis bald, Asario</div></div>',NULL,'1','2025-12-27 17:50:12','2025-12-27 18:11:55');
INSERT INTO `news` VALUES ('55','1','2026-01-24 09:30:12','1','Servercrash','<p>Nach einem Server-Crash musste ich alles neu initialisieren, aber jetzt sollte wieder alles funktionieren.</p><p>Auch die Pagination funktioniert jetzt wieder, somit ist wieder alles im Lot.</p>',NULL,'0','2026-01-24 09:30:12',NULL);

