DROP TABLE IF EXISTS `sessions`;
CREATE TABLE `sessions` (
  `id` varchar(255) NOT NULL,
  `user_id` bigint(20) unsigned DEFAULT NULL,
  `ip_address` varchar(45) DEFAULT NULL,
  `user_agent` text DEFAULT NULL,
  `payload` longtext NOT NULL,
  `last_activity` int(11) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `sessions_user_id_index` (`user_id`),
  KEY `sessions_last_activity_index` (`last_activity`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `tenant`;
CREATE TABLE `tenant` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `subdomain` varchar(255) NOT NULL,
  `database` varchar(255) NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `tenants_subdomain_unique` (`subdomain`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `texts`;
CREATE TABLE `texts` (
  `id` bigint(11) NOT NULL AUTO_INCREMENT,
  `pub` tinyint(2) NOT NULL,
  `position` bigint(11) NOT NULL,
  `headline` varchar(80) DEFAULT NULL,
  `text` text NOT NULL,
  `autoslug` varchar(50) NOT NULL,
  `users_id` bigint(11) NOT NULL,
  `created_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

INSERT INTO `texts` VALUES ('6','1','1','Hannemucks Biografie','1232232','bio','1','2025-03-24 17:13:26');
INSERT INTO `texts` VALUES ('8','1','2','Meine Musik','<p>asd<br />\nsd<br />\nsd</p><p>ds<br />\nsd<br />\nds</p>\n','music','1','2024-10-18 13:16:05');
INSERT INTO `texts` VALUES ('9','1','3','Künstliche Intelligenz Bei Asario.de','<p>Bildgenerierende KIs öffnen Türen, von denen wir lange nicht wussten, dass sie da sind. Sie nehmen ein paar Worte, schlicht wie Kieselsteine in der Hand, und formen daraus Bilder, die größer wirken als das, was man hineingelegt hat. Sie tun es ohne Zittern, ohne Zweifel, nur mit der stillen Genauigkeit einer Maschine, die gelernt hat, die Welt auf ihre Weise zu sehen.</p><p><br /></p><p>Man gibt ihnen eine Beschreibung, ein Gefühl, einen Gedanken. Und sie antworten mit Farben, mit Licht, mit Formen, die manchmal fremd wirken und manchmal erstaunlich vertraut. In Kunst, im Design, im Marketing – überall dort, wo Menschen Bilder brauchen – sind diese neuen Werkzeuge angekommen wie ein frischer Wind, der keine Erlaubnis braucht.</p><p><br /></p><p>Die Bilder, die mit „AI“ markiert sind, wurden mit NightCafe Studio geschaffen. Manche wurden danach weiter verfeinert, wie man ein Messer nachschärft, obwohl es schon gut schneidet. Doch der erste Schlag, die erste Kontur, stammt von der Maschine.</p>','ai','1','2024-10-21 09:55:17');
INSERT INTO `texts` VALUES ('12','1','4','Sie haben nicht die benötigten Rechte','<p>Diese Seite wurde gesperrt.<br /><br /><br /><br /><br />Wenden Sie sich an den Administrator falls Sie diese Funktion benötigen</p><p>Kontakt hier: <a href=\"http://www.marblefx.net/home/contacts\">http://www.marblefx.net/home/contacts</a></p>','no-rights','1','2024-10-21 12:29:42');
INSERT INTO `texts` VALUES ('14','1','8','Herzlich willkommen bei MarbleFX.de','Ihr Webdienstleister mit Profil.<div><br /></div><div> In Jahrelanger Arbeit haben wir <b>MCSL</b> entwickelt, <div>ein skalierbares Content Management System namens <b>M</b>arble <b>C</b>ontent <b>S</b>ystem <b>L</b>aravel. </div><div><br /></div><div>Dank Modularisierung sind vielfältige Einsatzmöglichkeiten umsetzbar.<br /><br />Von Einfacher Web-Visitenkarte (z.B. www.ra-c-henning.de) bis zum Webportal ist alles möglich.</div><div><br /></div><div>MCSL ist komplett Mandantenfähig was eine Aktualisierung erleichtert und alle Websites auf einem Code Niveau hält. Nie mehr verpasste Sicherheitsupdates. </div><div><br /></div><div>Sie haben was zu Sagen? Dann Sagen Sie es mit einer <b>MCSL</b> Webpage.</div></div>','mfx_welcome','1','2025-07-05 21:37:31');
INSERT INTO `texts` VALUES ('15','1','5','Kurzer Hinweis zum Changelog:','Das MCS Changelog ist inzwischen veraltet, weil das alte MCS nicht mehr genutzt wird. Stattdessen gibt’s jetzt MCSL – ein komplett neues System mit vielen frischen Features und Verbesserungen. Deshalb findest du <a href=\"/changelog\">hier</a> Updates und Infos zu <img src=\"/images/smilies/icon_mcsl.gif\" class=\"inline\" alt=\"icon_mcsl.gif\" />.','mfx_oldtodo','1','2025-07-22 18:49:01');
INSERT INTO `texts` VALUES ('16','1','6','Kontakt','<div><strong>Wir freuen uns, von Ihnen zu hören!</strong><br /></div><div>Ob Fragen, Feedback oder ein konkretes Anliegen – Asario steht Ihnen jederzeit zur Verfügung.</div><div>Nutzen Sie gerne die untenstehenden Kontaktdaten oder senden Sie uns direkt eine Nachricht</div><div>über das Kontaktformular.</div>','ContactsHeader','1','2025-08-10 11:16:51');
INSERT INTO `texts` VALUES ('17','1','7','Kontaktdaten','Paul Rieser<div>Dorfplatz 10</div><div>24576 Bimöhlen</div><div>Mobil: 0162/7716325</div><div>email: <a href=\"mailto:paul.rieser@marblefx.de\">paul.rieser%5Bat%5Dmarblefx.de</a></div>','ContactsInfos','1','2025-08-10 11:34:24');

DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `pub` tinyint(1) NOT NULL DEFAULT 0,
  `users_rights_id` tinyint(1) NOT NULL DEFAULT 5,
  `name` varchar(50) DEFAULT NULL,
  `nick_name` varchar(150) DEFAULT NULL,
  `password` varchar(155) NOT NULL,
  `password_old` varchar(155) DEFAULT NULL,
  `email` varchar(90) DEFAULT NULL,
  `first_name` varchar(30) DEFAULT NULL,
  `headline` varchar(255) DEFAULT NULL,
  `xis_friends` tinyint(1) DEFAULT NULL,
  `birthday` datetime DEFAULT NULL,
  `fbd` varchar(120) DEFAULT NULL,
  `website` varchar(255) DEFAULT NULL,
  `aufgabe` varchar(255) DEFAULT NULL,
  `location` varchar(150) DEFAULT NULL,
  `email_verified_at` datetime DEFAULT NULL,
  `xis_disabled` tinyint(1) DEFAULT NULL,
  `last_login_at` datetime DEFAULT NULL,
  `is_admin` tinyint(1) DEFAULT 1,
  `is_customer` tinyint(1) NOT NULL DEFAULT 1,
  `remember_token` varchar(255) DEFAULT NULL,
  `two_factor_secret` varchar(255) DEFAULT NULL,
  `two_factor_recovery_codes` text DEFAULT NULL,
  `two_factor_confirmed_at` datetime DEFAULT NULL,
  `two_factor_confirmed` tinyint(1) DEFAULT NULL,
  `two_factor_enabled` tinyint(2) DEFAULT NULL,
  `profile_photo_path` varchar(150) DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `google_id` text DEFAULT '',
  `uhash` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `nick` (`name`),
  UNIQUE KEY `email` (`email`)
) ENGINE=MyISAM AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci PACK_KEYS=0;


